{
  "name": "faalupega",
  "version": "0.1.0",
  "description": "Samoan Faalupega Lookup Tool — a searchable reference for traditional matai title records",
  "type": "module",
  "bin": {
    "faalupega": "./dist/bin/faalupega.js"
  },
  "dependencies": {
    "@inquirer/select": "^5.1.0",
    "commander": "^13.0.0"
  }
}

#!/usr/bin/env node
import { Command } from "commander";
import { villageCommand } from "../src/commands/village.js";
import { mataiCommand } from "../src/commands/matai.js";
import { setupCommand } from "../src/commands/setup.js";
import { loadConfig } from "../src/config.js";
import { DEFAULT_VERSION } from "../src/data/types.js";
const config = loadConfig();
const defaultVersion = config.version ?? DEFAULT_VERSION;
const program = new Command();
program
    .name("faalupega")
    .version("0.1.0")
    .helpOption("-h, --help", "Display help for command")
    .option("--data-version <version>", "Faalupega version year to query (e.g. 1930)", defaultVersion)
    .description(`Samoan Faalupega Lookup Tool

Faalupega is the traditional record of matai (chief) titles for each
village in Samoa. It documents the sacred hierarchy of titles, their
connections, ceremonial meeting grounds (malae-fono), houses of chiefs
(maota o alii), and kava cup names (igoa-ipu a alii).

This tool provides a searchable reference for these records.
All searches are partial and case-insensitive. Samoan diacritics
(macrons: a, e, i, o, u and glottal stops: \u02BB) are optional in queries
but preserved in output.

Usage examples:
  $ faalupega village Puipaa          Search by village name
  $ faalupega nuu Puipaa             Same search using Samoan alias
  $ faalupega village pui             Partial match
  $ faalupega matai Seiuli            Search by matai title
  $ faalupega suafa Fanene            Same search using Samoan alias
  $ faalupega village Puipaa --json   JSON output for agents`);
program.addCommand(villageCommand);
program.addCommand(mataiCommand);
program.addCommand(setupCommand);
program.parse();

import { Command } from "commander";
import { villages } from "../data/index.js";
import { formatVillageList } from "../format.js";
export const listCommand = new Command("list")
    .description("List all villages in the faalupega database")
    .option("--json", "Output as JSON for programmatic use")
    .action((opts) => {
    if (opts.json) {
        const summary = villages.map((v) => ({
            name: v.name,
            district: v.district,
            island: v.island,
        }));
        console.log(JSON.stringify(summary, null, 2));
    }
    else {
        console.log("Villages in database:\n");
        console.log(formatVillageList(villages));
    }
});

import { Command } from "commander";
import { findMataiMatches } from "../search.js";
import { formatMataiResult, formatVersionBox } from "../format.js";
export const mataiCommand = new Command("matai")
    .alias("suafa")
    .description("Search for a matai (chief) title and find which villages it belongs to. (Samoan: suafa)\n" +
    "Searches across all sections: Tulou, Malae-Fono, Maota o Alii,\n" +
    "O Igoa-Ipu a Alii, and Sa\u02BBotama\u02BBita\u02BBi.\n" +
    "Partial and case-insensitive. Diacritics optional.\n" +
    "Examples: faalupega matai Seiuli, faalupega suafa Fanene, faalupega matai ulu")
    .argument("<name>", "Matai/suafa title to search for")
    .option("--json", "Output as JSON for programmatic use")
    .action((name, opts, command) => {
    const globalOpts = command.parent?.opts();
    const version = globalOpts?.dataVersion;
    const results = findMataiMatches(name, version);
    if (results.length === 0) {
        console.error(`No villages found for matai title: ${name}`);
        process.exit(1);
    }
    if (opts.json) {
        const jsonResults = results.map((r) => ({
            village: { name: r.village.name, district: r.village.district, island: r.village.island, version: r.village.version },
            matches: r.matches,
        }));
        console.log(JSON.stringify(jsonResults, null, 2));
    }
    else {
        console.log(formatVersionBox(version ?? "1930"));
        console.log(results.map((r) => formatMataiResult(r)).join("\n\n"));
    }
});

import { Command } from "commander";
import select from "@inquirer/select";
import { loadConfig, saveConfig, getAvailableVersions, } from "../config.js";
export const setVersionCommand = new Command("set-version")
    .description("Set the default faalupega version.\n" +
    "Opens an interactive picker to choose from available versions.\n" +
    "Your choice is saved to ~/.faalupega/config.json.")
    .action(async () => {
    const config = loadConfig();
    const versions = getAvailableVersions();
    if (versions.length === 0) {
        console.error("No versions available.");
        process.exit(1);
    }
    const chosen = await select({
        message: "Select the default faalupega version:",
        choices: versions.map((v) => ({
            name: v,
            value: v,
            description: v === config.version ? "(current default)" : undefined,
        })),
        default: config.version ?? versions[0],
    });
    config.version = chosen;
    saveConfig(config);
    console.log(`\nDefault version set to: ${chosen}`);
});

import { Command } from "commander";
import select from "@inquirer/select";
import { loadConfig, saveConfig, getAvailableVersions, } from "../config.js";
import { printBanner } from "../format.js";
export const setupCommand = new Command("setup")
    .description("Interactive setup for faalupega.\n" +
    "Displays a welcome banner and lets you choose the default version.\n" +
    "Your choice is saved to ~/.faalupega/config.json.")
    .action(async () => {
    printBanner();
    const config = loadConfig();
    const versions = getAvailableVersions();
    if (versions.length === 0) {
        console.error("No versions available.");
        process.exit(1);
    }
    const chosen = await select({
        message: "Select the default faalupega version:",
        choices: versions.map((v) => ({
            name: v,
            value: v,
            description: v === config.version ? "(current default)" : undefined,
        })),
        default: config.version ?? versions[0],
    });
    config.version = chosen;
    saveConfig(config);
    console.log(`\nDefault version set to: ${chosen}`);
});

import { Command } from "commander";
import { findVillagesByName } from "../search.js";
import { formatVillage, formatVersionBox } from "../format.js";
export const villageCommand = new Command("village")
    .aliases(["nuu", "nu'u"])
    .description("Look up a village's faalupega by name. (Samoan: nuu / nu'u)\n" +
    "Searches are partial and case-insensitive. Diacritics (macrons, glottal stops) are optional.\n" +
    'Examples: faalupega village Puipaa, faalupega nuu Puipaa, faalupega village pui')
    .argument("<name>", "Village name to search for (diacritics optional)")
    .option("--json", "Output as JSON for programmatic use")
    .action((name, opts, command) => {
    const globalOpts = command.parent?.opts();
    const version = globalOpts?.dataVersion;
    const results = findVillagesByName(name, version);
    if (results.length === 0) {
        console.error(`No faalupega found for village: ${name}`);
        process.exit(1);
    }
    if (opts.json) {
        console.log(JSON.stringify(results.length === 1 ? results[0] : results, null, 2));
    }
    else {
        console.log(formatVersionBox(version ?? "1930"));
        if (results.length === 1) {
            console.log(formatVillage(results[0]));
        }
        else {
            console.log(`Found ${results.length} villages:\n`);
            results.forEach((v) => {
                console.log(formatVillage(v));
                console.log();
            });
        }
    }
});

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import { homedir } from "node:os";
import { villages } from "./data/index.js";
const CONFIG_DIR = join(homedir(), ".faalupega");
const CONFIG_FILE = join(CONFIG_DIR, "config.json");
export function getConfigPath() {
    return CONFIG_FILE;
}
export function loadConfig(configPath = CONFIG_FILE) {
    try {
        const raw = readFileSync(configPath, "utf-8");
        return JSON.parse(raw);
    }
    catch {
        return {};
    }
}
export function saveConfig(config, configPath = CONFIG_FILE) {
    const dir = configPath === CONFIG_FILE
        ? CONFIG_DIR
        : configPath.substring(0, configPath.lastIndexOf("/"));
    mkdirSync(dir, { recursive: true });
    writeFileSync(configPath, JSON.stringify(config, null, 2) + "\n", "utf-8");
}
export function getAvailableVersions() {
    const versions = new Set(villages.map((v) => v.version));
    return [...versions].sort();
}

import { allVillages } from "./villages/index.js";
export const villages = allVillages;
export function getVillages(version) {
    if (!version)
        return villages;
    return villages.filter((v) => v.version === version);
}
export { DEFAULT_VERSION } from "./types.js";

export { puipaa } from "./puipaa.js";
export { tafua } from "./tafua.js";
export { toamua } from "./toamua.js";
export { salelologa } from "./salelologa.js";
export { salelavalu } from "./salelavalu.js";
export { iva } from "./iva.js";
export { vaiafai } from "./vaiafai.js";
export { vaisaulu } from "./vaisaulu.js";
export { lalomalava } from "./lalomalava.js";
export { safua } from "./safua.js";
export { sapapalii } from "./sapapalii.js";
export { safotulafai } from "./safotulafai.js";
export { tapueleele } from "./tapueleele.js";
export { faga } from "./faga.js";
export { amoaSasae } from "./amoasasae.js";
export { amoaSisifo } from "./amoasisifo.js";
export { lealatele } from "./lealatele.js";
export { patamea } from "./patamea.js";

export const patamea = {
    version: "1930",
    name: "Patamea",
    district: "O le Itu-o-Tane",
    island: "Savaiʻi",
    tulou: [
        "Tulouna a oe le Pule to i-Malaeola, ma Gafuaga",
        "Tulouna a oe le Faleaana",
        "Tulouna a oe lau Afioga a Lauago",
    ],
    malaeFono: [
        { title: "Gafuaga", details: [] },
    ],
    maotaOAlii: [
        { title: "Lauago", details: ["Faletogō"] },
    ],
    igoaIpu: [
        { title: "Lauago", details: ["Tauaʻitao"] },
    ],
    saotamaitai: [
        { title: "Lauago", details: ["Sinanuʻu"] },
    ],
};

import { getVillages } from "./data/index.js";
/**
 * Normalize a Samoan string for comparison:
 * 1. Lowercase
 * 2. NFD decompose then strip combining diacritics (macrons)
 * 3. Remove glottal stop characters: ʻ (U+02BB), ' (U+2018), ' (U+2019), plain apostrophe
 */
export function normalize(input) {
    return input
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/[\u02BB\u2018\u2019']/g, "");
}
/**
 * Find villages by name. Partial, case-insensitive match after normalization.
 */
export function findVillagesByName(query, version) {
    const q = normalize(query);
    return getVillages(version).filter((v) => normalize(v.name).includes(q));
}
/**
 * Standard section order used everywhere:
 * Tulou → Malae-Fono → Maota o Alii → O Igoa-Ipu a Alii → Sa'otama'ita'i
 */
const SECTION_CONFIG = [
    { key: "tulou", label: "TULOU" },
    { key: "malaeFono", label: "MALAE-FONO" },
    { key: "maotaOAlii", label: "MAOTA O ALII" },
    { key: "maotaMaMalae", label: "MAOTA MA MALAE" },
    { key: "igoaIpu", label: "O IGOA-IPU A ALII" },
    { key: "saotamaitai", label: "SAʻOTAMAʻITAʻI" },
    { key: "aualumaOTane", label: "AUALUMA O TANE" },
];
function matchesQuery(text, q) {
    return normalize(text).includes(q);
}
function filterTitleEntries(entries, q) {
    return entries.filter((e) => {
        const titleNames = e.title.split(/,\s*/);
        const titleMatch = titleNames.some((name) => matchesQuery(name, q));
        const detailMatch = e.details.some((d) => matchesQuery(d, q));
        return titleMatch || detailMatch;
    });
}
/**
 * Search for a matai/suafa title across all village sections.
 * Returns focused results: only matching entries, grouped by section,
 * in standard section order.
 */
export function findMataiMatches(query, version) {
    const q = normalize(query);
    const results = [];
    for (const village of getVillages(version)) {
        const matches = [];
        for (const { key, label } of SECTION_CONFIG) {
            const data = village[key];
            if (key === "tulou" || key === "aualumaOTane") {
                const stringData = data ?? [];
                const matching = stringData.filter((t) => matchesQuery(t, q));
                if (matching.length > 0) {
                    matches.push({
                        section: label,
                        entries: matching.map((t) => ({ title: t, details: [] })),
                    });
                }
            }
            else {
                const entries = data ?? [];
                const filtered = filterTitleEntries(entries, q);
                if (filtered.length > 0) {
                    matches.push({ section: label, entries: filtered });
                }
            }
        }
        if (matches.length > 0) {
            results.push({ village, matches });
        }
    }
    return results;
}

# `@inquirer/core`

The `@inquirer/core` package is the library enabling the creation of Inquirer prompts.

It aims to implements a lightweight API similar to React hooks - but without JSX.

# Installation

<table>
<tr>
  <th>npm</th>
  <th>yarn</th>
</tr>
<tr>
<td>

```sh
npm install @inquirer/core
```

</td>
<td>

```sh
yarn add @inquirer/core
```

</td>
</tr>
</table>

# Usage

## Basic concept

Visual terminal apps are at their core strings rendered onto the terminal.

The most basic prompt is a function returning a string that'll be rendered in the terminal. This function will run every time the prompt state change, and the new returned string will replace the previously rendered one. The prompt cursor appears after the string.

Wrapping the rendering function with `createPrompt()` will setup the rendering layer, inject the state management utilities, and wait until the `done` callback is called.

```ts
import { createPrompt } from '@inquirer/core';

const input = createPrompt((config, done) => {
  // Implement logic

  return '? My question';
});

// And it is then called as
const answer = await input({
  /* config */
});
```

## Hooks

State management and user interactions are handled through hooks. Hooks are common [within the React ecosystem](https://react.dev/reference/react/hooks), and Inquirer reimplement the common ones.

### State hook

State lets a component “remember” information like user input. For example, an input prompt can use state to store the input value, while a list prompt can use state to track the cursor index.

`useState` declares a state variable that you can update directly.

```ts
import { createPrompt, useState } from '@inquirer/core';

const input = createPrompt((config, done) => {
  const [index, setIndex] = useState(0);

  // ...
```

### Keypress hook

Almost all prompts need to react to user actions. In a terminal, this is done through typing.

`useKeypress` allows you to react to keypress events, and access the prompt line.

```ts
const input = createPrompt((config, done) => {
  useKeypress((key) => {
    if (key.name === 'enter') {
      done(answer);
    }
  });

  // ...
```

Behind the scenes, Inquirer prompts are wrappers around [readlines](https://nodejs.org/api/readline.html). Aside the keypress event object, the hook also pass the active readline instance to the event handler.

```ts
const input = createPrompt((config, done) => {
  useKeypress((key, readline) => {
    setValue(readline.line);
  });

  // ...
```

### Ref hook

Refs let a prompt hold some information that isn’t used for rendering, like a class instance or a timeout ID. Unlike with state, updating a ref does not re-render your prompt. Refs are an “escape hatch” from the rendering paradigm.

`useRef` declares a ref. You can hold any value in it, but most often it’s used to hold a timeout ID.

```ts
const input = createPrompt((config, done) => {
  const timeout = useRef(null);

  // ...
```

### Effect Hook

Effects let a prompt connect to and synchronize with external systems. This includes dealing with network or animations.

`useEffect` connects a component to an external system.

```ts
const chat = createPrompt((config, done) => {
  useEffect(() => {
    const connection = createConnection(roomId);
    connection.connect();
    return () => connection.disconnect();
  }, [roomId]);

  // ...
```

### Performance hook

A common way to optimize re-rendering performance is to skip unnecessary work. For example, you can tell Inquirer to reuse a cached calculation or to skip a re-render if the data has not changed since the previous render.

`useMemo` lets you cache the result of an expensive calculation.

```ts
const todoSelect = createPrompt((config, done) => {
  const visibleTodos = useMemo(() => filterTodos(todos, tab), [todos, tab]);

  // ...
```

### Rendering hooks

#### Prefix / loading

All default prompts, and most custom ones, uses a prefix at the beginning of the prompt line. This helps visually delineate different questions, and provides a convenient area to render a loading spinner.

`usePrefix` is a built-in hook to do this.

```ts
const input = createPrompt((config, done) => {
  const prefix = usePrefix({ status });

  return `${prefix} My question`;
});
```

#### Pagination

When looping through a long list of options (like in the `select` prompt), paginating the results appearing on the screen at once can be necessary. The `usePagination` hook is the utility used within the `select` and `checkbox` prompts to cycle through the list of options.

Pagination works by taking in the list of options and returning a subset of the rendered items that fit within the page. The hook takes in a few options. It needs a list of options (`items`), and a `pageSize` which is the number of lines to be rendered. The `active` index is the index of the currently selected/selectable item. The `loop` option is a boolean that indicates if the list should loop around when reaching the end: this is the default behavior. The pagination hook renders items only as necessary, so it takes a function that can render an item at an index, including an `active` state, called `renderItem`.

```js
export default createPrompt((config, done) => {
  const [active, setActive] = useState(0);

  const allChoices = config.choices.map((choice) => choice.name);

  const page = usePagination({
    items: allChoices,
    active: active,
    renderItem: ({ item, index, isActive }) => `${isActive ? ">" : " "}${index}. ${item.toString()}`
    pageSize: config.pageSize,
    loop: config.loop,
  });

  return `... ${page}`;
});
```

## `createPrompt()` API

As we saw earlier, the rendering function should return a string, and eventually call `done` to close the prompt and return the answer.

```ts
const input = createPrompt((config, done) => {
  const [value, setValue] = useState();

  useKeypress((key, readline) => {
    if (key.name === 'enter') {
      done(answer);
    } else {
      setValue(readline.line);
    }
  });

  return `? ${config.message} ${value}`;
});
```

The rendering function can also return a tuple of 2 string (`[string, string]`.) The first string represents the prompt. The second one is content to render under the prompt, like an error message. The text input cursor will appear after the first string.

```ts
const number = createPrompt((config, done) => {
  // Add some logic here

  return [`? My question ${input}`, `! The input must be a number`];
});
```

### Typescript

If using typescript, `createPrompt` takes 2 generic arguments.

```ts
// createPrompt<Value, Config>
const input = createPrompt<string, { message: string }>(// ...
```

The first one is the type of the resolved value

```ts
const answer: string = await input();
```

The second one is the type of the prompt config; in other words the interface the created prompt will provide to users.

```ts
const answer = await input({
  message: 'My question',
});
```

## Key utilities

Listening for keypress events inside an inquirer prompt is a very common pattern. To ease this, we export a few utility functions taking in the keypress event object and return a boolean:

- `isEnterKey()`
- `isBackspaceKey()`
- `isSpaceKey()`
- `isUpKey()` - Note: this utility will handle vim and emacs keybindings (up, `k`, and `ctrl+p`)
- `isDownKey()` - Note: this utility will handle vim and emacs keybindings (down, `j`, and `ctrl+n`)
- `isNumberKey()` one of 1, 2, 3, 4, 5, 6, 7, 8, 9, 0

## Theming

Theming utilities will allow you to expose customization of the prompt style. Inquirer also has a few standard theme values shared across all the official prompts.

To allow standard customization:

```ts
import { createPrompt, usePrefix, makeTheme, type Theme } from '@inquirer/core';
import type { PartialDeep } from '@inquirer/type';

type PromptConfig = {
  theme?: PartialDeep<Theme>;
};

export default createPrompt<string, PromptConfig>((config, done) => {
  const theme = makeTheme(config.theme);

  const prefix = usePrefix({ status, theme });

  return `${prefix} ${theme.style.highlight('hello')}`;
});
```

To setup a custom theme:

```ts
import { createPrompt, makeTheme, type Theme } from '@inquirer/core';
import type { PartialDeep } from '@inquirer/type';

type PromptTheme = {};

const promptTheme: PromptTheme = {
  icon: '!',
};

type PromptConfig = {
  theme?: PartialDeep<Theme<PromptTheme>>;
};

export default createPrompt<string, PromptConfig>((config, done) => {
  const theme = makeTheme(promptTheme, config.theme);

  const prefix = usePrefix({ status, theme });

  return `${prefix} ${theme.icon}`;
});
```

The [default theme keys cover](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/core/src/lib/theme.ts):

```ts
type DefaultTheme = {
  prefix: string | { idle: string; done: string };
  spinner: {
    interval: number;
    frames: string[];
  };
  style: {
    answer: (text: string) => string;
    message: (text: string, status: 'idle' | 'done' | 'loading') => string;
    error: (text: string) => string;
    defaultAnswer: (text: string) => string;
    help: (text: string) => string;
    highlight: (text: string) => string;
    key: (text: string) => string;
  };
};
```

# Examples

You can refer to any `@inquirer/prompts` prompts for real examples:

- [Confirm Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/confirm/src/index.ts)
- [Input Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/input/src/index.ts)
- [Password Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/password/src/index.ts)
- [Editor Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/editor/src/index.ts)
- [Select Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/select/src/index.ts)
- [Checkbox Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/checkbox/src/index.ts)
- [Rawlist Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/rawlist/src/index.ts)
- [Expand Prompt](https://github.com/SBoudrias/Inquirer.js/blob/main/packages/expand/src/index.ts)

```ts
import { styleText } from 'node:util';
import {
  createPrompt,
  useState,
  useKeypress,
  isEnterKey,
  usePrefix,
  type Status,
} from '@inquirer/core';

const confirm = createPrompt<boolean, { message: string; default?: boolean }>(
  (config, done) => {
    const [status, setStatus] = useState<Status>('idle');
    const [value, setValue] = useState('');
    const prefix = usePrefix({});

    useKeypress((key, rl) => {
      if (isEnterKey(key)) {
        const answer = value ? /^y(es)?/i.test(value) : config.default !== false;
        setValue(answer ? 'yes' : 'no');
        setStatus('done');
        done(answer);
      } else {
        setValue(rl.line);
      }
    });

    let formattedValue = value;
    let defaultValue = '';
    if (status === 'done') {
      formattedValue = styleText('cyan', value);
    } else {
      defaultValue = styleText('dim', config.default === false ? ' (y/N)' : ' (Y/n)');
    }

    const message = styleText('bold', config.message);
    return `${prefix} ${message}${defaultValue} ${formattedValue}`;
  },
);

/**
 *  Which then can be used like this:
 */
const answer = await confirm({ message: 'Do you want to continue?' });
```

